import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import { Store, ShoppingBasket, LayoutDashboard } from 'lucide-react';

// Importación de tus componentes
import DashboardVendedor from './components/DashboardVendedor';
import VistaCliente from './components/VistaCliente';

function App() {
  return (
    <Router>
      <div style={appContainer}>
        {/* BARRA DE NAVEGACIÓN SIMPLE */}
        <nav style={navStyle}>
          <div style={navContent}>
            <Link to="/" style={logoStyle}>
              <ShoppingBasket size={28} color="#e67e22" />
              <span style={{ marginLeft: '10px' }}>SuperOnline</span>
            </Link>

            <div style={linksWrapper}>
              <Link to="/" style={linkStyle}>
                <ShoppingBasket size={20} /> Tienda
              </Link>
              <Link to="/admin" style={linkStyleAdmin}>
                <LayoutDashboard size={20} /> Panel Vendedor
              </Link>
            </div>
          </div>
        </nav>

        {/* CONFIGURACIÓN DE RUTAS */}
        <main style={mainContent}>
          <Routes>
            {/* Ruta para el Cliente (Inicio) */}
            <Route path="/" element={<VistaCliente />} />

            {/* Ruta para el Vendedor (Carga de Productos) */}
            <Route path="/admin" element={<DashboardVendedor />} />
          </Routes>
        </main>

        <footer style={footerStyle}>
          <p>© 2024 Supermercado Online - Sistema de Gestión de Inventario Automático</p>
        </footer>
      </div>
    </Router>
  );
}

// --- ESTILOS DE LA ESTRUCTURA ---
const appContainer = {
  minHeight: '100vh',
  display: 'flex',
  flexDirection: 'column',
  background: '#f8fafc'
};

const navStyle = {
  background: '#fff',
  borderBottom: '1px solid #e2e8f0',
  padding: '15px 0',
  position: 'sticky',
  top: 0,
  zIndex: 1000
};

const navContent = {
  maxWidth: '1200px',
  margin: '0 auto',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '0 20px'
};

const logoStyle = {
  display: 'flex',
  alignItems: 'center',
  textDecoration: 'none',
  fontSize: '1.4rem',
  fontWeight: '900',
  color: '#1e293b'
};

const linksWrapper = {
  display: 'flex',
  gap: '20px'
};

const linkStyle = {
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  textDecoration: 'none',
  color: '#64748b',
  fontWeight: 'bold',
  fontSize: '0.9rem'
};

const linkStyleAdmin = {
  ...linkStyle,
  background: '#1e293b',
  color: 'white',
  padding: '8px 15px',
  borderRadius: '10px'
};

const mainContent = {
  flex: 1,
  width: '100%',
  maxWidth: '1200px',
  margin: '0 auto'
};

const footerStyle = {
  textAlign: 'center',
  padding: '20px',
  fontSize: '0.8rem',
  color: '#94a3b8',
  background: '#fff',
  borderTop: '1px solid #e2e8f0'
};

export default App;
